#include <stdio.h>
#include <stdbool.h>
bool isPrime(int n) {
    if (n <= 1) return false;
    if (n == 2) return true;
    if (n % 2 == 0) return false;
    for (int i = 3; i * i <= n; i += 2) {
        if (n % i == 0) return false;
    }
    return true;
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int x, y;
        scanf("%d %d", &x, &y);
        int sum = x + y;
        int i = 1;
        while (true) {
            if (isPrime(sum + i)) {
                printf("%d\n", i);
                break;
            }
            i++;
        }
    }
    return 0;
}

